DROP TABLE IF EXISTS order_items;DROP TABLE IF EXISTS orders;DROP TABLE IF EXISTS products;DROP TABLE IF EXISTS categories;DROP TABLE IF EXISTS users;
CREATE TABLE users(id SERIAL PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(255) UNIQUE NOT NULL,password VARCHAR(255) NOT NULL,role VARCHAR(20) NOT NULL DEFAULT 'USER',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE categories(id SERIAL PRIMARY KEY,name VARCHAR(100) NOT NULL,slug VARCHAR(120) UNIQUE NOT NULL,image_url TEXT);
CREATE TABLE products(id SERIAL PRIMARY KEY,name VARCHAR(255) NOT NULL,slug VARCHAR(255) UNIQUE NOT NULL,description TEXT,price NUMERIC(10,2) NOT NULL DEFAULT 0,sale_price NUMERIC(10,2),stock INT NOT NULL DEFAULT 0,image_url TEXT,category_id INT NOT NULL REFERENCES categories(id),is_featured BOOLEAN DEFAULT false,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE orders(id SERIAL PRIMARY KEY,user_id INT NOT NULL REFERENCES users(id) ON DELETE CASCADE,total NUMERIC(10,2) NOT NULL,status VARCHAR(50) NOT NULL DEFAULT 'PLACED',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE order_items(id SERIAL PRIMARY KEY,order_id INT NOT NULL REFERENCES orders(id) ON DELETE CASCADE,product_id INT NOT NULL REFERENCES products(id),quantity INT NOT NULL,price NUMERIC(10,2) NOT NULL);
CREATE INDEX idx_products_category ON products(category_id);CREATE INDEX idx_products_name ON products USING gin(to_tsvector('english',name));CREATE INDEX idx_orders_user ON orders(user_id);
